const React = require("react");
const ReactDOM = require("react-dom/client");

class App extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      selected: [],
      suggestions: [],
    };
  }

  handleChange = (e) => {
    this.setState({ selected: e.target.value.split(",").map((s) => s.trim()) });
  };

  handleSubmit = () => {
    fetch("http://localhost:3000/api/suggest", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ selectedItems: this.state.selected }),
    })
      .then((res) => res.json())
      .then((data) => this.setState({ suggestions: data }))
      .catch((err) => console.error(err));
  };

  render() {
    return React.createElement("div", null, [
      React.createElement(
        "h2",
        { key: "h2" },
        "Nhập sản phẩm (cách nhau bằng dấu phẩy):"
      ),
      React.createElement("input", {
        key: "input",
        type: "text",
        onChange: this.handleChange,
      }),
      React.createElement(
        "button",
        {
          key: "button",
          onClick: this.handleSubmit,
        },
        "Gợi ý"
      ),
      React.createElement(
        "ul",
        { key: "ul" },
        this.state.suggestions.map((s, i) =>
          React.createElement(
            "li",
            { key: i },
            `${s.items.join(" + ")} (${(s.support * 100).toFixed(1)}%)`
          )
        )
      ),
    ]);
  }
}

const root = ReactDOM.createRoot(document.getElementById("root"));
root.render(React.createElement(App));
